import logging

logger = logging.getLogger('security')

def log_access(user_id, resource, action, success):
    logger.info(json.dumps({
        'event': 'access_attempt',
        'user_id': user_id,
        'resource': resource,
        'action': action,
        'success': success,
        'timestamp': datetime.utcnow().isoformat()
    }))
